<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\LessonPlan;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class LessonPlanRepository extends BaseRepository{    public function __construct(LessonPlan $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function findByTeacher(int $employeeId): Collection    {        return $this->findByField('employee_id', $employeeId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('lesson_date', [$startDate, $endDate])->get();    }    public function getByTopic(string $topic): Collection    {        return $this->query()->where('topic', 'like', "%{$topic}%")->get();    }    public function searchLessonPlans(string $keyword): Collection    {        return $this->query()->where('title', 'like', "%{$keyword}%")->orWhere('topic', 'like', "%{$keyword}%")->orWhere('objectives', 'like', "%{$keyword}%")->get();    }    public function getCompletedPlans(): Collection    {        return $this->query()->where('status', 'completed')->get();    }    public function getPendingPlans(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function markAsCompleted(int $id): bool    {        return $this->update($id, ['status' => 'completed', 'completed_at' => now()]);    }    public function getByClassAndSubject(int $classId, int $subjectId): Collection    {        return $this->query()->where('class_id', $classId)->where('subject_id', $subjectId)->orderBy('lesson_date', 'asc')->get();    }}